)

//go:embed index.html
var indexHTML []byte

//go:embed safecast-square-ct.png
var logoPNG []byte

const systemPrompt = `Safecast radiation monitoring assistant with REAL-TIME sensor data and historical archives.

**Tool Selection**
- Current/live data: sensor_current (returns actual CPM readings), list_sensors (metadata/discovery only)
- Time-series from fixed sensors: sensor_history
- Extreme readings with locations: query_extreme_readings
- Statistics: radiation_stats
- Historical surveys: query_radiation, search_area, list_tracks
- NEVER use query_radiation for current data (historical only)
- NEVER use radiation_stats for specific extreme location queries
- NEVER use list_sensors when the user wants radiation readings — use sensor_current instead

**Device type names** (exact values in the database):
- bGeigieZen → "geigiecast-zen" (IDs like geigiecast-zen:65002)
- bGeigie → "geigiecast" (IDs like geigiecast:62007) — MOBILE only
- Pointcast → "pointcast" (IDs like pointcast:10042)
- Solarcast → "solarcast"
- Notehub/Radnote/Blues → "notehub" (IDs like note:dev:867648049123019)
- nGeigie → "ngeigie" (IDs like ngeigie:101)
- Direct TCP → "device-tcp" (IDs like safecast:3474557222)

**Data Types**
- Real-time fixed stations: geigiecast-zen, pointcast, solarcast, notehub, ngeigie, device-tcp → sensor_current or sensor_history
- Mobile surveys only: geigiecast → query_radiation, list_tracks, device_history
- CPM → µSv/h: multiply by ~0.0069 (LND 7318)
- NEVER use device_history for any fixed sensor type — use sensor_current instead

**"Latest readings" at a location: ALWAYS do BOTH steps**
1. Call query_radiation (historical mobile data)
2. Call sensor_current with geographic bounds (fixed real-time sensors)
Report both results. Only say "no real-time data" after sensor_current returns empty results.

**Looking up a specific fixed sensor by device ID** (any non-geigiecast type):
- Use sensor_current with device_id parameter, NOT device_history
- Note: notehub device IDs contain colons, e.g. "note:dev:867648049123019" — pass the full string as device_id
- device_history is ONLY for mobile bGeigie (geigiecast) devices

**Radius Selection** (query_radiation, sensor_current):
Address: 500-1000m | District: 2000-5000m | Village: 5000-10000m | City: 15-25km | Metro: 30-50km
Always state radius used.

**Formatting**
- Hide "_ai_generated_note" field (internal use only)
- **CRITICAL: ALL devices/coords MUST be clickable map links:**
  * Devices: [pointcast:10042](https://simplemap.safecast.org/?lat=LAT&lon=LON&zoom=15)
  * Tracks: [track_id](https://simplemap.safecast.org/?lat=LAT&lon=LON&zoom=12)
  * Coords: [37.72°N, 140.48°E](https://simplemap.safecast.org/?lat=37.72&lon=140.48&zoom=15)
  * NEVER plain device names or "Visit: https://..." text
- Sensor/track data: ALWAYS use markdown tables (not lists)
- Table columns: Device ID, Type, Location, Reading, Timestamp
- Timestamp: ALWAYS display in UTC — convert from any timezone, format as "2026-03-03 22:14 UTC"
- Concise coords: "37.48°N, 140.48°E"

Be concise. Ask for clarification if location unclear.`

// ── Anthropic API types ────────────────────────────────────────────────────

type anthropicTool struct {
	Name        string          `json:"name"`
	Description string          `json:"description"`
	InputSchema json.RawMessage `json:"input_schema"`
}

// contentBlock covers all content block variants we care about.
type contentBlock struct {
	Type      string          `json:"type"`
	Text      string          `json:"text,omitempty"`
	ID        string          `json:"id,omitempty"`
	Name      string          `json:"name,omitempty"`
	Input     json.RawMessage `json:"input,omitempty"`
	ToolUseID string          `json:"tool_use_id,omitempty"`
	Content   string          `json:"content,omitempty"`
}

type anthropicMessage struct {
	Role    string      `json:"role"`
	Content interface{} `json:"content"` // string or []contentBlock
}

type anthropicRequest struct {
	Model     string             `json:"model"`
	MaxTokens int                `json:"max_tokens"`
	System    string             `json:"system"`
	Messages  []anthropicMessage `json:"messages"`
	Tools     []anthropicTool    `json:"tools,omitempty"`
}

type anthropicResponse struct {
	Content    []contentBlock `json:"content"`
	StopReason string         `json:"stop_reason"`
	Error      *struct {
		Type    string `json:"type"`
		Message string `json:"message"`
	} `json:"error,omitempty"`
}

// ── Streaming helpers (chunked HTTP / NDJSON) ──────────────────────────────

type chunk struct {
	Type  string `json:"type"`
	Text  string `json:"text,omitempty"`
	Error string `json:"error,omitempty"`
}

func writeChunk(w http.ResponseWriter, c chunk) {
	data, _ := json.Marshal(c)
	data = append(data, '\n')
	w.Write(data)
	if f, ok := w.(http.Flusher); ok {
		f.Flush()
	}
}

// writeChunkBuffered either buffers the chunk or writes immediately
func writeChunkBuffered(w http.ResponseWriter, c chunk, buffer *[]chunk, useBuffer bool) {
	if useBuffer {
		*buffer = append(*buffer, c)
	} else {
		writeChunk(w, c)
	}
}

// flushBuffer writes all buffered chunks at once
func flushBuffer(w http.ResponseWriter, buffer []chunk) {
	for _, c := range buffer {
		writeChunk(w, c)
	}
}

// ── Anthropic call ─────────────────────────────────────────────────────────

func callAnthropic(ctx context.Context, apiKey, model string, messages []anthropicMessage, tools []anthropicTool) (*anthropicResponse, error) {
	reqBody := anthropicRequest{
		Model:     model,
		MaxTokens: 4096,
		System:    systemPrompt,
		Messages:  messages,
		Tools:     tools,
	}
	body, err := json.Marshal(reqBody)
	if err != nil {
		return nil, err
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, "https://api.anthropic.com/v1/messages", bytes.NewReader(body))
	if err != nil {
		return nil, err
	}
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("x-api-key", apiKey)
	req.Header.Set("anthropic-version", "2023-06-01")

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	raw, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, err
	}

	var ar anthropicResponse
	if err := json.Unmarshal(raw, &ar); err != nil {
		return nil, fmt.Errorf("parse response: %w", err)
	}
	if ar.Error != nil {
		return nil, fmt.Errorf("anthropic %s: %s", ar.Error.Type, ar.Error.Message)
	}
	return &ar, nil
}

// ── MCP tool conversion ────────────────────────────────────────────────────

func mcpToolsToAnthropic(tools []mcp.Tool) []anthropicTool {
	var out []anthropicTool
	for _, t := range tools {
		schema, _ := json.Marshal(t.InputSchema)
		out = append(out, anthropicTool{
			Name:        t.Name,
			Description: t.Description,
			InputSchema: json.RawMessage(schema),
		})
	}
	return out
}

// ── Chat handler ───────────────────────────────────────────────────────────

func handleChat(mcpURL, apiKey, model string) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		// CORS preflight
		w.Header().Set("Access-Control-Allow-Origin", "*")
		w.Header().Set("Access-Control-Allow-Methods", "POST, OPTIONS")
		w.Header().Set("Access-Control-Allow-Headers", "Content-Type")
		if r.Method == http.MethodOptions {
			w.WriteHeader(http.StatusNoContent)
			return
		}

		// Detect if request comes through CloudFront
		// CloudFront adds these headers: CloudFront-Viewer-Country, CloudFront-Forwarded-Proto, etc.
		isCloudfFront := r.Header.Get("CloudFront-Viewer-Country") != "" ||
			r.Header.Get("CloudFront-Forwarded-Proto") != "" ||
			r.Header.Get("X-Amz-Cf-Id") != ""

		// Debug logging
		log.Printf("Chat request: CloudFront=%v, Headers: CF-Country=%q, CF-Proto=%q, X-Amz-Cf-Id=%q",
			isCloudfFront,
			r.Header.Get("CloudFront-Viewer-Country"),
			r.Header.Get("CloudFront-Forwarded-Proto"),
			r.Header.Get("X-Amz-Cf-Id"))

		// Chunked HTTP streaming — NDJSON, one JSON object per line, flushed immediately.
		// CloudFront buffers responses, so we collect chunks and send all at once.
		w.Header().Set("Content-Type", "application/x-ndjson")
		if !isCloudfFront {
			w.Header().Set("Transfer-Encoding", "chunked")
			w.Header().Set("X-Accel-Buffering", "no") // nginx: don't buffer
		}
		w.Header().Set("Cache-Control", "no-cache, no-store")

		// Buffer for CloudFront requests
		var buffer []chunk

		ctx := r.Context()

		var chatReq struct {
			Message string              `json:"message"`
			History []anthropicMessage `json:"history,omitempty"`
		}
		if err := json.NewDecoder(r.Body).Decode(&chatReq); err != nil || chatReq.Message == "" {
			w.WriteHeader(http.StatusBadRequest)
			writeChunkBuffered(w, chunk{Type: "error", Error: "invalid request: message required"}, &buffer, isCloudfFront)
			if isCloudfFront {
				flushBuffer(w, buffer)
			}
			return
		}

		// ── Connect to MCP server ──────────────────────────────────────────
		mc, err := mcpclient.NewStreamableHttpClient(mcpURL)
		if err != nil {
			writeChunkBuffered(w, chunk{Type: "error", Error: fmt.Sprintf("MCP connect: %v", err)}, &buffer, isCloudfFront)
			if isCloudfFront {
				flushBuffer(w, buffer)
			}
			return
		}
		defer mc.Close()

		if _, err := mc.Initialize(ctx, mcp.InitializeRequest{
			Params: mcp.InitializeParams{
				ProtocolVersion: mcp.LATEST_PROTOCOL_VERSION,
				ClientInfo:      mcp.Implementation{Name: "safecast-web-chat", Version: "1.0.0"},
			},
		}); err != nil {
			writeChunkBuffered(w, chunk{Type: "error", Error: fmt.Sprintf("MCP init: %v", err)}, &buffer, isCloudfFront)
			if isCloudfFront {
				flushBuffer(w, buffer)
			}
			return
		}

		toolsResult, err := mc.ListTools(ctx, mcp.ListToolsRequest{})
		if err != nil {
			writeChunkBuffered(w, chunk{Type: "error", Error: fmt.Sprintf("list tools: %v", err)}, &buffer, isCloudfFront)
			if isCloudfFront {
				flushBuffer(w, buffer)
			}
			return
		}
		tools := mcpToolsToAnthropic(toolsResult.Tools)

		// ── Agentic loop ───────────────────────────────────────────────────
		// Start with conversation history (if provided) and append new user message
		messages := chatReq.History
		if messages == nil {
			messages = []anthropicMessage{}
		}
		messages = append(messages, anthropicMessage{Role: "user", Content: chatReq.Message})

		for {
			resp, err := callAnthropic(ctx, apiKey, model, messages, tools)
			if err != nil {
				writeChunkBuffered(w, chunk{Type: "error", Error: err.Error()}, &buffer, isCloudfFront)
				if isCloudfFront {
					flushBuffer(w, buffer)
				}
				return
			}

			messages = append(messages, anthropicMessage{
				Role:    "assistant",
				Content: resp.Content,
			})

			var toolUses []contentBlock
			for _, block := range resp.Content {
				switch block.Type {
				case "text":
					// Stream each text block as it arrives (or buffer if CloudFront)
					writeChunkBuffered(w, chunk{Type: "text", Text: block.Text}, &buffer, isCloudfFront)
				case "tool_use":
					toolUses = append(toolUses, block)
				}
			}

			if resp.StopReason == "end_turn" || len(toolUses) == 0 {
				break
			}

			// ── Execute tool calls via MCP ─────────────────────────────────
			var toolResults []contentBlock
			for _, tu := range toolUses {
				var args map[string]any
				_ = json.Unmarshal(tu.Input, &args)

				callReq := mcp.CallToolRequest{}
				callReq.Params.Name = tu.Name
				callReq.Params.Arguments = args

				var resultText string
				toolResult, err := mc.CallTool(ctx, callReq)
				if err != nil {
					resultText = fmt.Sprintf("tool error: %v", err)
				} else {
					for _, c := range toolResult.Content {
						if tc, ok := c.(mcp.TextContent); ok {
							resultText += tc.Text
						}
					}
				}

				toolResults = append(toolResults, contentBlock{
					Type:      "tool_result",
					ToolUseID: tu.ID,
					Content:   resultText,
				})
			}

			messages = append(messages, anthropicMessage{
				Role:    "user",
				Content: toolResults,
			})
		}

		// Send final "done" chunk
		writeChunkBuffered(w, chunk{Type: "done"}, &buffer, isCloudfFront)

		// For CloudFront requests, flush all buffered chunks at once
		if isCloudfFront {
			flushBuffer(w, buffer)
		}
	}
}

// ── Main ───────────────────────────────────────────────────────────────────

func main() {
	apiKey := os.Getenv("ANTHROPIC_API_KEY")
	if apiKey == "" {
		log.Fatal("ANTHROPIC_API_KEY is required")
	}
	model := os.Getenv("CLAUDE_MODEL")
	if model == "" {
		model = "claude-sonnet-4-5"
	}
	mcpURL := os.Getenv("MCP_URL")
	if mcpURL == "" {
		mcpURL = "http://localhost:3333/mcp-http"
	}
	port := os.Getenv("PORT")
	if port == "" {
		port = "3334"
	}

	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "text/html; charset=utf-8")
		w.Write(indexHTML)
	})
	http.HandleFunc("/safecast-square-ct.png", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "image/png")
		w.Header().Set("Cache-Control", "public, max-age=86400")
		w.Write(logoPNG)
	})
	http.HandleFunc("/chat", handleChat(mcpURL, apiKey, model))
	http.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
		fmt.Fprint(w, "ok")
	})

	log.Printf("Safecast web-chat on :%s  MCP→%s  model=%s", port, mcpURL, model)
	log.Fatal(http.ListenAndServe(":"+port, nil))
}

package main

import (
	"context"
	"fmt"
	"strings"

	"github.com/mark3labs/mcp-go/mcp"
)

var sensorCurrentToolDef = mcp.NewTool("sensor_current",
	mcp.WithDescription("Get the MOST RECENT readings from REAL-TIME fixed sensors. USE THIS TOOL for: bGeigieZen (type=geigiecast-zen, IDs like geigiecast-zen:65002), Pointcast (type=pointcast, IDs like pointcast:10042), Solarcast (type=solarcast), Notehub/Radnote (type=notehub, IDs like note:dev:867648049123019), nGeigie (type=ngeigie, IDs like ngeigie:101), device-tcp (IDs like safecast:3474557222). Use when users ask about 'current', 'latest', 'live', 'now', or 'real-time' data, OR to look up a specific fixed sensor by device ID. When searching by location, always call this tool AND query_radiation together to cover both fixed and mobile sources. DO NOT use device_history for any of these fixed sensor types — device_history is ONLY for mobile bGeigie (type=geigiecast). DO NOT use query_radiation for current data. CPM = counts per minute (convert to µSv/h using ~0.0069 for LND 7318). Always report the captured_at timestamp. Present data objectively without personal pronouns."),
	mcp.WithString("device_id",
		mcp.Description("Specific device ID to get latest reading from"),
	),
	mcp.WithNumber("min_lat",
		mcp.Description("Southern boundary for geographic filter"),
		mcp.Min(-90), mcp.Max(90),
	),
	mcp.WithNumber("max_lat",
		mcp.Description("Northern boundary for geographic filter"),
		mcp.Min(-90), mcp.Max(90),
	),
	mcp.WithNumber("min_lon",
		mcp.Description("Western boundary for geographic filter"),
		mcp.Min(-180), mcp.Max(180),
	),
	mcp.WithNumber("max_lon",
		mcp.Description("Eastern boundary for geographic filter"),
		mcp.Min(-180), mcp.Max(180),
	),
	mcp.WithNumber("limit",
		mcp.Description("Maximum number of readings to return (default: 25, max: 1000)"),
		mcp.Min(1), mcp.Max(1000),
		mcp.DefaultNumber(25),
	),
	mcp.WithReadOnlyHintAnnotation(true),
)

func handleSensorCurrent(ctx context.Context, req mcp.CallToolRequest) (*mcp.CallToolResult, error) {
	deviceID := req.GetString("device_id", "")
	minLat := req.GetFloat("min_lat", -90)
	maxLat := req.GetFloat("max_lat", 90)
	minLon := req.GetFloat("min_lon", -180)
	maxLon := req.GetFloat("max_lon", 180)
	limit := req.GetInt("limit", 25)

	if limit < 1 || limit > 1000 {
		return mcp.NewToolResultError("Limit must be between 1 and 1000"), nil
	}

	if dbAvailable() {
		return sensorCurrentDB(ctx, deviceID, minLat, maxLat, minLon, maxLon, limit)
	}

	// Fallback to API if database not available
	return mcp.NewToolResultError("Database connection required for sensor_current tool. Please ensure DATABASE_URL is set to access real-time sensor data."), nil
}

func sensorCurrentDB(ctx context.Context, deviceID string, minLat, maxLat, minLon, maxLon float64, limit int) (*mcp.CallToolResult, error) {
	// Check what tables are available in the database
	tablesQuery := `
		SELECT table_name 
		FROM information_schema.tables 
		WHERE table_schema = 'public'
		ORDER BY table_name
	`

	tableRows, err := queryRows(ctx, tablesQuery)
	if err != nil {
		return mcp.NewToolResultError("Could not query database schema: " + err.Error()), nil
	}

	// Look for tables that might contain real-time sensor data
	availableTables := make([]string, len(tableRows))
	realtimeTable := ""
	for i, row := range tableRows {
		if tableName, ok := row["table_name"].(string); ok {
			availableTables[i] = tableName
			// Check for possible real-time sensor data tables
			if tableName == "realtime_measurements" || 
			   tableName == "measurements_realtime" || 
			   tableName == "sensors" ||
			   tableName == "devices" {
				realtimeTable = tableName
			}
		}
	}

	if realtimeTable == "" {
		// If no real-time table found, return available tables for debugging
		result := map[string]any{
			"message": "No known real-time sensor data tables found in database.",
			"available_tables": availableTables,
			"suggestion": "Real-time sensor data may not be available through this database connection.",
		}
		return jsonResult(result)
	}

	var query string
	var args []interface{}

	if deviceID != "" {
		// Get latest reading from specific device
		query = fmt.Sprintf(`
			SELECT
				id,
				device_id,
				COALESCE(device_name, device_id) AS device_name,
				value,
				COALESCE(unit, 'µSv/h') AS unit,
				to_timestamp(measured_at) AS captured_at,
				lat AS latitude,
				lon AS longitude,
				COALESCE(transport, '') AS transport
			FROM %s
			WHERE device_id = $1
			  AND to_timestamp(measured_at) <= NOW()
			ORDER BY measured_at DESC
			LIMIT 1`, realtimeTable)

		args = []interface{}{deviceID}
	} else {
		// Get latest readings from all sensors in geographic area
		query = fmt.Sprintf(`
			SELECT
				rm.id,
				rm.device_id,
				COALESCE(rm.device_name, rm.device_id) AS device_name,
				rm.value,
				COALESCE(rm.unit, 'µSv/h') AS unit,
				to_timestamp(rm.measured_at) AS captured_at,
				rm.lat AS latitude,
				rm.lon AS longitude,
				COALESCE(rm.transport, '') AS transport
			FROM %s rm
			INNER JOIN (
				SELECT device_id, MAX(measured_at) as max_measured_at
				FROM %s
				WHERE lat >= $1 AND lat <= $2 AND lon >= $3 AND lon <= $4
				  AND to_timestamp(measured_at) <= NOW()
				GROUP BY device_id
			) latest ON rm.device_id = latest.device_id AND rm.measured_at = latest.max_measured_at
			WHERE rm.lat >= $1 AND rm.lat <= $2 AND rm.lon >= $3 AND rm.lon <= $4
			  AND to_timestamp(rm.measured_at) <= NOW()
			ORDER BY rm.measured_at DESC
			LIMIT $5`, realtimeTable, realtimeTable)

		args = []interface{}{minLat, maxLat, minLon, maxLon, limit}
	}

	rows, err := queryRows(ctx, query, args...)
	if err != nil {
		return mcp.NewToolResultError(fmt.Sprintf("Error querying %s table: %v", realtimeTable, err)), nil
	}

	readings := make([]map[string]any, len(rows))
	for i, r := range rows {
		// Fix incorrect unit: Geiger counters report in CPM (counts per minute), not CPS
		unit := r["unit"]
		if unitStr, ok := unit.(string); ok {
			unit = strings.ReplaceAll(strings.ReplaceAll(unitStr, "cps", "cpm"), "CPS", "CPM")
		}

		readings[i] = map[string]any{
			"id":          r["id"],
			"device_id":   r["device_id"],
			"device_name": r["device_name"],
			"value":       r["value"],
			"unit":        unit,
			"captured_at": r["captured_at"],
			"location": map[string]any{
				"latitude":  r["latitude"],
				"longitude": r["longitude"],
			},
			"type": r["transport"],
		}
	}

	result := map[string]any{
		"count":    len(readings),
		"source":   "database",
		"readings": readings,
		"table_used": realtimeTable,
		"available_tables": availableTables,
		"_ai_hint": "CRITICAL INSTRUCTIONS: (1) **REAL-TIME DATA**: This tool returns the MOST RECENT readings from fixed sensors. Readings with future timestamps (sensor clock errors) are automatically filtered out. Always check the 'captured_at' timestamp and report it to the user - if the data is more than 24 hours old, mention this to the user and suggest checking if the sensor is still active. (2) **UNITS**: CPM means 'counts per minute' NOT 'counts per second'. Always convert to µSv/h using detector-specific factors (LND 7318: ~0.0069 µSv/h per CPM). (3) **TOOL SELECTION**: For latest sensor data, use 'sensor_current'. For historical trends, use 'sensor_history'. For mobile measurements, use 'device_history'. Do NOT use 'query_radiation' for current sensor data as it searches the historical markers table. (4) **PRESENTATION**: State objective facts only - no personal pronouns (I, we, you), exclamations, or conversational phrases. Example: 'Device X reading: 50 CPM (0.35 µSv/h) at [time]' NOT 'I found a reading...'",
		"_ai_generated_note": "This data was retrieved by an AI assistant using Safecast tools. The interpretation and presentation of this data may be influenced by the AI system.",
	}

	return jsonResult(result)
}

package main

import (
	"context"

	"github.com/mark3labs/mcp-go/mcp"
)

var queryRadiationToolDef = mcp.NewTool("query_radiation",
	mcp.WithDescription("Find radiation measurements near a geographic location. Returns measurements within a specified radius of the given coordinates. IMPORTANT: Every response includes an _ai_generated_note field. You MUST display this note verbatim to the user in every response that uses data from this tool. CRITICAL: Present all findings in an objective, scientific manner without using personal pronouns (I, we, I'll, you) or conversational language (Perfect!, Great!). Format as factual statements only."),
	mcp.WithNumber("lat",
		mcp.Description("Latitude (-90 to 90)"),
		mcp.Min(-90), mcp.Max(90),
		mcp.Required(),
	),
	mcp.WithNumber("lon",
		mcp.Description("Longitude (-180 to 180)"),
		mcp.Min(-180), mcp.Max(180),
		mcp.Required(),
	),
	mcp.WithNumber("radius_m",
		mcp.Description("Search radius in meters (default: 1500, max: 50000)"),
		mcp.Min(25), mcp.Max(50000),
		mcp.DefaultNumber(1500),
	),
	mcp.WithNumber("limit",
		mcp.Description("Maximum number of results to return (default: 25, max: 10000)"),
		mcp.Min(1), mcp.Max(10000),
		mcp.DefaultNumber(25),
	),
	mcp.WithReadOnlyHintAnnotation(true),
)

func handleQueryRadiation(ctx context.Context, req mcp.CallToolRequest) (*mcp.CallToolResult, error) {
	lat, err := req.RequireFloat("lat")
	if err != nil {
		return mcp.NewToolResultError(err.Error()), nil
	}
	lon, err := req.RequireFloat("lon")
	if err != nil {
		return mcp.NewToolResultError(err.Error()), nil
	}
	radiusM := req.GetFloat("radius_m", 1500)
	limit := req.GetInt("limit", 25)

	if lat < -90 || lat > 90 {
		return mcp.NewToolResultError("Latitude must be between -90 and 90"), nil
	}
	if lon < -180 || lon > 180 {
		return mcp.NewToolResultError("Longitude must be between -180 and 180"), nil
	}
	if radiusM < 25 || radiusM > 50000 {
		return mcp.NewToolResultError("Radius must be between 25 and 50000 meters"), nil
	}
	if limit < 1 || limit > 10000 {
		return mcp.NewToolResultError("Limit must be between 1 and 10000"), nil
	}

	if dbAvailable() {
		return queryRadiationDB(ctx, lat, lon, radiusM, limit)
	}
	return queryRadiationAPI(ctx, lat, lon, radiusM, limit)
}

func queryRadiationDB(ctx context.Context, lat, lon, radiusM float64, limit int) (*mcp.CallToolResult, error) {
	// Use a bounding box pre-filter (&&) to hit the geometry spatial index first,
	// then refine with ST_DWithin on geography for precise meter-based distance.
	// Without the bbox filter, the geography cast bypasses the index → full table scan → timeout.
	//
	// PERFORMANCE: Use a subquery to filter and sort BEFORE joining to uploads/users.
	// This limits the join to only N rows instead of joining 90k+ rows then sorting.
	query := `
		WITH top_markers AS (
			SELECT m.id, m.doserate, m.date, m.lat, m.lon,
				m.device_id, m.altitude, m.detector, m.trackid, m.has_spectrum, m.geom
			FROM markers m
			WHERE m.geom && ST_Expand(ST_SetSRID(ST_MakePoint($2, $1), 4326), $3 / 111000.0)
			  AND ST_DWithin(m.geom::geography, ST_SetSRID(ST_MakePoint($2, $1), 4326)::geography, $3)
			ORDER BY m.date DESC
			LIMIT $4
		)
		SELECT m.id, m.doserate AS value, 'µSv/h' AS unit,
			to_timestamp(m.date) AS captured_at,
			m.lat AS latitude, m.lon AS longitude,
			m.device_id, m.altitude AS height, m.detector,
			m.trackid, m.has_spectrum,
			ST_Distance(m.geom::geography, ST_SetSRID(ST_MakePoint($2, $1), 4326)::geography) AS distance_m,
			u.internal_user_id, usr.username AS uploader_username, usr.email AS uploader_email
		FROM top_markers m
		LEFT JOIN uploads u ON u.track_id = m.trackid
		LEFT JOIN users usr ON u.internal_user_id = usr.id::text
		ORDER BY m.date DESC`

	rows, err := queryRows(ctx, query, lat, lon, radiusM, limit)
	if err != nil {
		return mcp.NewToolResultError(err.Error()), nil
	}

	// Get total count (with same bbox pre-filter for performance)
	countRow, _ := queryRow(ctx, `
		SELECT count(*) AS total
		FROM markers m
		WHERE m.geom && ST_Expand(ST_SetSRID(ST_MakePoint($2, $1), 4326), $3 / 111000.0)
		  AND ST_DWithin(m.geom::geography, ST_SetSRID(ST_MakePoint($2, $1), 4326)::geography, $3)`,
		lat, lon, radiusM)
	total := 0
	if countRow != nil {
		if t, ok := countRow["total"]; ok {
			switch v := t.(type) {
			case int64:
				total = int(v)
			case float64:
				total = int(v)
			}
		}
	}

	measurements := make([]map[string]any, len(rows))
	for i, r := range rows {
		measurement := map[string]any{
			"id":    r["id"],
			"value": r["value"],
			"unit":  r["unit"],
			"captured_at": r["captured_at"],
			"location": map[string]any{
				"latitude":  r["latitude"],
				"longitude": r["longitude"],
			},
			"device_id":    r["device_id"],
			"height":       r["height"],
			"detector":     r["detector"],
			"track_id":     r["trackid"],
			"has_spectrum":  r["has_spectrum"],
			"distance_m":   r["distance_m"],
		}

		// Add uploader information if available
		if uploaderUsername, ok := r["uploader_username"]; ok && uploaderUsername != nil && uploaderUsername != "" {
			measurement["uploader"] = map[string]any{
				"username": uploaderUsername,
				"email":    r["uploader_email"],
			}
		}

		measurements[i] = measurement
	}

	result := map[string]any{
		"count":           len(measurements),
		"total_available": total,
		"source":          "database",
		"query": map[string]any{
			"lat":      lat,
			"lon":      lon,
			"radius_m": radiusM,
		},
		"measurements": measurements,
		"_ai_hint": "CRITICAL INSTRUCTIONS: (1) The .unit. field indicates measurement units - CPM means .counts per minute. NOT .counts per second.. Always interpret and report CPM values as counts per minute. (2) Present all data in a purely scientific, factual manner. NEVER use personal pronouns (I, we, I.ll, I.m, you, your), exclamations (!, Perfect, Great, Excellent), or conversational phrases. Format responses as objective statements: .Latest reading: X CPM at location Y. NOT .I found a reading of X CPM. or .Perfect! The sensor shows..... State only objective facts and measurements.",
		"_next_step": "REQUIRED: This result contains ONLY historical mobile survey data. You MUST now call sensor_current with a bounding box around the same location to check for real-time fixed sensors (bGeigieZen, Pointcast, Notehub, nGeigie, etc.). Do not report 'no real-time data' until sensor_current has been called and returned empty results.",
		"_ai_generated_note": "This data was retrieved by an AI assistant using Safecast tools. The interpretation and presentation of this data may be influenced by the AI system.",
	}

	return jsonResult(result)
}

func queryRadiationAPI(ctx context.Context, lat, lon, radiusM float64, limit int) (*mcp.CallToolResult, error) {
	resp, err := client.GetLatestNearby(ctx, lat, lon, radiusM, limit)
	if err != nil {
		return mcp.NewToolResultError(err.Error()), nil
	}

	markers, _ := resp["markers"].([]any)
	normalized := make([]map[string]any, 0, len(markers))
	for _, raw := range markers {
		if m, ok := raw.(map[string]any); ok {
			normalized = append(normalized, normalizeLatestMarker(m))
		}
	}

	result := map[string]any{
		"count":  len(normalized),
		"source": "api",
		"query": map[string]any{
			"lat":      lat,
			"lon":      lon,
			"radius_m": radiusM,
